import FolderCard from './FolderCard';

/**
 * LoadingFolderCard.tsx
 *  Description: Placeholder for loading folder card when a folder is being added with new data
 */
export default function LoadingFolderCard() {
	return (
		<FolderCard
			folder={{ id: 'loading', name: 'Loading...' }}
			isSelected={false}
			onSelect={() => {}}
			onDelete={() => {}}
			onCreateBookmark={() => {}}
			onDrop={() => {}}
			draggable={false}
		/>
	);
}
